29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_RATE = 0.1;
31	
32	const BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_PREMIUM = 60;
44	const CURSE_SURCHARGE_RATE = 0.5;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
47	const LOYALTY_THRESHOLD_YEARS = 2;
48	const LOYALTY_DISCOUNT_RATE = 0.2;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	const DEDUCTIBLE = 100;
51	
52	const INSURANCE_VALUE: Record<string, number> = {
53	  sword: 1000,
54	  rune: 250,
55	};
56	
57	function calculateBasePremium(items: Item[]): number {
58	  const typeCounts: Record<string, number> = {};
59	  for (const item of items) {
60	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
61	  }
62	
63	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
64	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
65	      ? BLOCK_PREMIUM
66	      : count * BASE_PREMIUM[type];
67	    return total + premium;
68	  }, 0);
69	}
70	
71	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
72	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
73	    ? basePremium * LOYALTY_DISCOUNT_RATE
74	    : 0;
75	}
76	
77	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
78	  return (customer.quoteNumber ?? 1) >= 2
79	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
80	    : 0;
81	}
82	
83	function calculateItemSurcharges(items: Item[]): number {
84	  return items.reduce((total, item) => {
85	    const itemBasePremium = BASE_PREMIUM[item.type];
86	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
87	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
88	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
89	      : 0;
90	    return total + curseSurcharge + enchantmentSurcharge;
91	  }, 0);
92	}
93	
94	function calculateInsuranceCap(policyItems: Item[]): number {
95	  const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
96	  return insuranceSum * 2;
97	}
98	
99	function calculateClaimPayout(damages: Damage[]): number {
100	  return damages.reduce((sum, damage) => sum + Math.max(damage.amount - DEDUCTIBLE, 0), 0);
101	}
102	
103	export function processScenario(scenario: Scenario): unknown[] {
104	  const results: unknown[] = [];
105	
106	  for (const step of scenario.steps) {
107	    if (step.type === "quote") {
108	      const items = step.items!;
109	      const basePremium = calculateBasePremium(items);
110	      const itemSurcharges = calculateItemSurcharges(items);
111	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
112	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
113	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
114	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
115	      results.push({ premium });
116	    } else if (step.type === "claim") {
117	      const policyItems = scenario.steps[step.policy!].items!;
118	      const cap = calculateInsuranceCap(policyItems);
119	      const totalPayout = calculateClaimPayout(step.damages!);
120	      const payout = Math.min(totalPayout, cap);
121	      const remainingCap = cap - payout;
122	      results.push({ payout, remainingCap });
123	    }
124	  }
125	
126	  return results;
127	}
