110	      const itemSurcharges = calculateItemSurcharges(items);
111	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
112	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
113	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
114	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
115	      results.push({ premium });
116	    } else if (step.type === "claim") {
117	      const policyItems = scenario.steps[step.policy!].items!;
118	      const cap = calculateInsuranceCap(policyItems);
119	      const totalPayout = calculateClaimPayout(step.damages!);
120	      const payout = Math.min(totalPayout, cap);
121	      const remainingCap = cap - payout;
122	      results.push({ payout, remainingCap });
123	    }
124	  }
125	
126	  return results;
127	}

